import React, { useEffect, useState } from 'react';
import api from '../api';

function UserDashboard() {
  const [user, setUser] = useState(null);
const datas=
  useEffect(() => {

    const fetch=async(id)=>{
      try{
   const res= await api.post(`/users/${id}`);
   setUser(res.data)
      }

      catch(err){
        console.log(err)
      }}
  }, []);

  if (!user) return <div className="text-center mt-5">Loading...</div>;

  return (
    <div className="container mt-4">
      {/* Header */}
      <div className="text-center mb-5">
        <h2 className="fw-bold">Welcome, {user.name} 👋</h2>
        <p className="text-muted">Here’s your dashboard overview</p>
      </div>

      {/* Profile and Stats Row */}
      <div className="row g-4">
        {/* Profile Card */}
        <div className="col-md-4">
          <div className="card shadow-sm border-0 h-100">
            <div className="card-body text-center">
              <img src="https://via.placeholder.com/100" className="rounded-circle mb-3" alt="avatar" />
              <h5 className="card-title">{user.name}</h5>
              <p className="card-text">🎓 {user.Degree}</p>
              <p className="text-muted small">Roll No: {user.RollNo}</p>
              <span className="badge bg-primary">{user.role}</span>
            </div>
          </div>
        </div>

        {/* Stats / Features */}
        <div className="col-md-8">
          <div className="row g-3">
            <div className="col-sm-6">
              <div className="card text-white bg-success h-100">
                <div className="card-body">
                  <h6 className="card-title">Attendance</h6>
                  <p className="card-text display-6">92%</p>
                </div>
              </div>
            </div>
            <div className="col-sm-6">
              <div className="card text-white bg-info h-100">
                <div className="card-body">
                  <h6 className="card-title">Courses</h6>
                  <p className="card-text display-6">5</p>
                </div>
              </div>
            </div>
            <div className="col-12">
              <div className="card border-0 shadow-sm">
                <div className="card-body">
                  <h6 className="card-title">Recent Activity</h6>
                  <ul className="list-group list-group-flush">
                    <li className="list-group-item">✔️ Submitted Assignment 3</li>
                    <li className="list-group-item">🔔 Notification: Exam schedule updated</li>
                    <li className="list-group-item">📅 Attended Math class today</li>
                  </ul>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div className="text-center mt-5 text-muted small">
        Made with ❤️ using Bootstrap 5
      </div>
    </div>
  );
}

export default UserDashboard;
